1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("returns empty for empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("a single live cell dies (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("two adjacent live cells both die (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("a live cell with 2 live neighbors survives", () => {
15	    // Blinker: vertical column. Center (0,1) has 2 live neighbors and survives.
16	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
17	    expect(result).toContainEqual([0, 1]);
18	  });
19	  it("a live cell with more than 3 live neighbors dies (overpopulation)", () => {
20	    // Center (1,1) has 4 live neighbors (the 4 corners), should die.
21	    const result = nextGeneration([[0, 0], [2, 0], [1, 1], [0, 2], [2, 2]]);
22	    expect(result).not.toContainEqual([1, 1]);
23	  });
24	  it("a dead cell with exactly 3 live neighbors becomes alive (reproduction)", () => {
25	    // Cells form an L; dead cell (1,1) has exactly 3 live neighbors (0,0), (1,0), (0,1).
26	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
27	    expect(result).toContainEqual([1, 1]);
28	  });
