const deadNeighborCandidates = (cells: Cell[]): Cell[] => {
  const candidates: Cell[] = [];
  const seen = new Set<string>();
  const isLive = new Set(cells.map(([x, y]) => `${x},${y}`));
  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const nx = x + dx;
        const ny = y + dy;
        const key = `${nx},${ny}`;
        if (isLive.has(key)) continue;
        if (seen.has(key)) continue;
        seen.add(key);
        candidates.push([nx, ny]);
      }
    }
  }
  return candidates;
};

export const nextGeneration = (cells: Cell[]): Cell[] => {
  const survivors = cells.filter((cell) => countLiveNeighbors(cell, cells) === 2);
  const births = deadNeighborCandidates(cells).filter(
    (cell) => countLiveNeighbors(cell, cells) === 3
  );
  return [...survivors, ...births];
};
